import{_ as t,o as n,c as o,ag as r}from"./chunks/framework.BBBcTwIo.js";const f=JSON.parse('{"title":"Filtering and missing INVOKE rows","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/filtering-and-missing-invoke.md","filePath":"how-to/filtering-and-missing-invoke.md"}'),i={name:"how-to/filtering-and-missing-invoke.md"};function s(a,e,l,g,h,d){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="filtering-and-missing-invoke-rows" tabindex="-1">Filtering and missing INVOKE rows <a class="header-anchor" href="#filtering-and-missing-invoke-rows" aria-label="Permalink to &quot;Filtering and missing INVOKE rows&quot;">​</a></h1><p><strong>Goal:</strong> Find events in a busy log, or diagnose why an expected <strong>INVOKE</strong> line never appears.</p><h2 id="text-filter-search" tabindex="-1">Text filter (search) <a class="header-anchor" href="#text-filter-search" aria-label="Permalink to &quot;Text filter (search)&quot;">​</a></h2><p>The toolbar search matches (case-insensitive) against:</p><ul><li>Event name</li><li>Owner type name</li><li>Subscriber type name (for SUB/UNSUB)</li></ul><div class="danger custom-block"><p class="custom-block-title">Stale filter hides real rows</p><p>If you previously typed a narrow query (for example a substring of <strong>one</strong> event), other events <strong>disappear</strong> from the list even though they were recorded. <strong>Clear the search field</strong> when debugging “missing” events.</p><p>On a fresh Play session, the Event Monitor window may reset filters; behavior depends on version — when in doubt, clear the field manually.</p></div><h2 id="action-toggles" tabindex="-1">Action toggles <a class="header-anchor" href="#action-toggles" aria-label="Permalink to &quot;Action toggles&quot;">​</a></h2><p>Disable <strong>INVOKE</strong>, <strong>SUB</strong>, or <strong>UNSUB</strong> to hide that category entirely. Ensure <strong>INVOKE</strong> is enabled if you expect invocation lines.</p><h2 id="recording-off" tabindex="-1">Recording off <a class="header-anchor" href="#recording-off" aria-label="Permalink to &quot;Recording off&quot;">​</a></h2><p>If <strong>Record</strong> is disabled, no new rows are appended. The toolbar shows a clear <strong>recording off</strong> state.</p><h2 id="why-invoke-might-be-absent-even-when-the-event-ran" tabindex="-1">Why INVOKE might be absent (even when the event ran) <a class="header-anchor" href="#why-invoke-might-be-absent-even-when-the-event-ran" aria-label="Permalink to &quot;Why INVOKE might be absent (even when the event ran)&quot;">​</a></h2><ol><li><strong>No subscribers</strong> — <code>event?.Invoke()</code> often <strong>does not</strong> call <code>Invoke</code> when the delegate is null; no IL path means no injected <strong>RecordInvoke</strong> for that fire.</li><li><strong>IL pattern</strong> — invocation through a <strong>helper</strong> or <strong>reflection</strong> may not match the injector (see <a href="./../reference/il-limitations.html">IL patterns and limitations</a>).</li><li><strong>Assembly not instrumented</strong> — code in skipped assemblies is not rewritten.</li><li><strong><code>recordingEnabled: false</code></strong> in <code>ilpp_settings.json</code> — ILPP does not inject (see <a href="./ilpp-diagnostics.html">ILPP diagnostics and settings</a>).</li></ol><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../troubleshooting/faq.html">Troubleshooting &amp; FAQ</a></li><li><a href="./../guide/quick-start.html">Quick Start</a></li></ul>',14)])])}const m=t(i,[["render",s]]);export{f as __pageData,m as default};
